@dataclass(frozen=True)
class KernelResult:
    status: str
    out_dir: Path
    files: tuple[str, ...]
    simulation: dict[str, Any]
    verilator: dict[str, Any] | None = None
    synthesis: dict[str, Any] | None = None
    coverage_level: str = "synthetic_fixture"
    implementation_stage: str = "not_run"
    contract_gate: dict[str, Any] | None = None
    numeric_policy: dict[str, Any] | None = None
    extra_report: dict[str, Any] | None = None

    def to_dict(self) -> dict[str, Any]:
        result = {
            "status": self.status,
            "out": str(self.out_dir),
            "files": list(self.files),
            "coverage_level": self.coverage_level,
            "implementation_stage": self.implementation_stage,
            "simulation": self.simulation,
            "verilator": self.verilator,
            "synthesis": self.synthesis,
            "contract_gate": self.contract_gate,
        }
        if self.numeric_policy is not None:
            result["numeric_policy"] = self.numeric_policy
        if self.extra_report is not None:
            result.update(self.extra_report)
        return result


def _model_level_harness_decoder_layers(dispatch_plan: dict[str, Any]) -> int:
    decoder_layers = dispatch_plan.get("model", {}).get("decoder_layers")
    if not isinstance(decoder_layers, int):
        raise ValueError("dispatch_plan.model.decoder_layers must be an integer")
    if decoder_layers <= 0:
        raise ValueError("dispatch_plan.model.decoder_layers must be positive")
    return decoder_layers


def _model_level_harness_initial_state(width: int) -> np.ndarray:
    if width <= 0:
        raise ValueError("hidden_fixture_width must be positive")
    return np.arange(width, dtype=np.int64) - (width // 2)


def _model_level_harness_vector_step(state: np.ndarray, layer_index: int) -> np.ndarray:
    idx = np.arange(state.size, dtype=np.int64)
    rotated = np.roll(state, (layer_index % state.size) + 1)
    attention = rotated + ((idx + 1) * (layer_index + 3))
    mlp = (state * ((layer_index % 5) + 2)) - ((idx % 3) * (layer_index + 1))
    return attention + mlp + np.int64(layer_index)


def _model_level_harness_reference_step(state: list[int], layer_index: int) -> list[int]:
    width = len(state)
    shift = (layer_index % width) + 1
    result: list[int] = []
    for idx, value in enumerate(state):
        rotated = state[(idx - shift) % width]
        attention = rotated + ((idx + 1) * (layer_index + 3))
        mlp = (value * ((layer_index % 5) + 2)) - ((idx % 3) * (layer_index + 1))
        result.append(int(attention + mlp + layer_index))
    return result


def build_model_level_execution_harness_report(
    dispatch_plan: dict[str, Any],
    *,
    hidden_fixture_width: int = 8,
    tolerance_lsb: int = 0,
) -> dict[str, Any]:
    """Run a non-HDL model-level loop and compare it with an independent Python reference."""

    decoder_layers = _model_level_harness_decoder_layers(dispatch_plan)
    state = _model_level_harness_initial_state(hidden_fixture_width)
    reference_state = [int(value) for value in state.tolist()]
    trace: list[dict[str, Any]] = []
    max_abs_error = 0

    for layer_index in range(decoder_layers):
        state = _model_level_harness_vector_step(state, layer_index)
        reference_state = _model_level_harness_reference_step(reference_state, layer_index)
        diff = np.abs(state - np.asarray(reference_state, dtype=np.int64))
        layer_max_error = int(diff.max()) if diff.size else 0
        max_abs_error = max(max_abs_error, layer_max_error)
        trace.append(
            {
                "layer": layer_index,
                "vector_checksum": int(state.sum()),
                "reference_checksum": int(sum(reference_state)),
                "max_abs_error": layer_max_error,
            }
        )

    comparison_passed = max_abs_error <= tolerance_lsb
    executed_layer_count = len(trace)
    full_model_layers_executed = executed_layer_count >= decoder_layers

    return {
        "artifact": "model_level_execution_harness_report",
        "status": "passed" if comparison_passed and full_model_layers_executed else "failed",
        "model": dispatch_plan.get("model", {}).get("name"),
        "required_decoder_layers": decoder_layers,
        "executed_layer_count": executed_layer_count,
        "full_model_layers_executed": full_model_layers_executed,
        "target_16_layer_iteration": executed_layer_count >= 16,
        "python_reference_comparison": {
            "passed": comparison_passed,
            "tolerance_lsb": tolerance_lsb,
            "max_abs_error": max_abs_error,
            "implementation": "numpy_vectorized_decoder_loop",
            "reference": "independent_scalar_python_decoder_loop",
        },
        "model_level_harness": {
            "kind": "non_hdl_deterministic_decoder_layer_loop",
            "source": "dispatch_plan.model.decoder_layers",
            "hidden_fixture_width": hidden_fixture_width,
            "bounded_two_layer_fixture_reused": False,
            "layer_indices": [entry["layer"] for entry in trace],
        },
        "execution_trace": trace,
        "final_output_vector": [int(value) for value in state.tolist()],
        "final_reference_vector": [int(value) for value in reference_state],
        "board_level_signoff": False,
        "does_not_claim": [
            "full_llama_execution_readiness",
            "board_level_ZCU104_signoff",
            "real_time_LLaMA_inference_performance",
            "hardware_lab_runtime_validation",
            "target_scale_hidden_size_numeric_accuracy",
            "real_checkpoint_logits_or_sampling",
        ],
        "remaining_risks": [
            "non-HDL harness only; downstream full_llama_execution_evidence.json must still be written separately",
            "numeric harness validates 16-layer scheduling and Python agreement, not target-scale LLaMA logits",
        ],
    }


def write_model_level_execution_harness_report(
    dispatch_plan: dict[str, Any],
    out_dir: Path,
    *,
    hidden_fixture_width: int = 8,
    tolerance_lsb: int = 0,
) -> dict[str, Any]:
    report = build_model_level_execution_harness_report(
        dispatch_plan,
        hidden_fixture_width=hidden_fixture_width,
        tolerance_lsb=tolerance_lsb,
    )
    out_dir.mkdir(parents=True, exist_ok=True)
    if report["status"] == "passed":
        (out_dir / "model_level_execution_harness_report.json").write_text(
            json.dumps(report, indent=2),
            encoding="utf-8",
        )
    return report


def synthetic_llama_mlir() -> str:
    return """module {
  func.func @llama_decoder_block(%arg0: tensor<1x4xi8>) -> (tensor<1x4xi8>) {
    %0 = "llm.RMSNorm"(%arg0) {onnx_node_name = "input_layernorm"} : (tensor<1x4xi8>) -> tensor<1x4xi8>
    %1 = "onnx.MatMul"(%0, %q_weight) {onnx_node_name = "q_proj"} : (tensor<1x4xi8>, tensor<4x4xi4>) -> tensor<1x4xi32>
    %2 = "onnx.MatMul"(%0, %k_weight) {onnx_node_name = "k_proj"} : (tensor<1x4xi8>, tensor<4x4xi4>) -> tensor<1x4xi32>
    %3 = "llm.RoPE"(%1) {onnx_node_name = "rope_q"} : (tensor<1x4xi32>) -> tensor<1x4xi32>
    %4 = "llm.Softmax"(%3, %2) {onnx_node_name = "attention_softmax"} : (tensor<1x4xi32>, tensor<1x4xi32>) -> tensor<1x4xi8>
    %5 = "onnx.MatMul"(%4, %o_weight) {onnx_node_name = "o_proj"} : (tensor<1x4xi8>, tensor<4x4xi4>) -> tensor<1x4xi32>
    %6 = "llm.RMSNorm"(%5) {onnx_node_name = "post_attention_layernorm"} : (tensor<1x4xi32>) -> tensor<1x4xi8>
    %7 = "onnx.MatMul"(%6, %up_weight) {onnx_node_name = "up_proj"} : (tensor<1x4xi8>, tensor<8x4xi4>) -> tensor<1x8xi32>
    %8 = "llm.SiLU"(%7) {onnx_node_name = "silu"} : (tensor<1x8xi32>) -> tensor<1x8xi32>
    %9 = "onnx.MatMul"(%8, %down_weight) {onnx_node_name = "down_proj"} : (tensor<1x8xi32>, tensor<4x8xi4>) -> tensor<1x4xi32>
    return %9 : tensor<1x4xi32>
  }
}
"""


def _inspect_mlir_source(out_dir: Path, config: AgentConfig | None) -> tuple[Path, dict[str, Any]]:
    provided_mlir = config.model.mlir_graph if config is not None else None
    if provided_mlir is None:
        mlir_path = out_dir / "synthetic_llama_block.mlir"
        mlir_path.write_text(synthetic_llama_mlir(), encoding="utf-8")
        return mlir_path, {
            "analysis_source": "synthetic_llama_block_mlir",
            "source_kind": "synthetic_fixture",
            "source_path": str(mlir_path),
            "target_claim_allowed_by_source": False,
        }

    source_path = Path(provided_mlir).expanduser()
    if not source_path.exists():
        raise FileNotFoundError(f"model.mlir_graph does not exist: {source_path}")
    mlir_path = out_dir / "model_graph.mlir"
    mlir_path.write_text(source_path.read_text(encoding="utf-8", errors="ignore"), encoding="utf-8")
    return mlir_path, {
        "analysis_source": "provided_model_mlir_file",
        "source_kind": "provided_mlir",
        "source_path": str(source_path),
        "copied_path": str(mlir_path),
        "target_claim_allowed_by_source": True,
    }


def _fallback_llama32_1b_metadata(model_name: str, config: AgentConfig | None) -> dict[str, Any]:
    sequence_length = config.model.sequence_length if config is not None else 2048
    return {
        "name": model_name,
        "family": "llama_decoder_only_transformer",
        "target_checkpoint": model_name == "meta-llama/Llama-3.2-1B",
        "metadata_source": "semantic_fixture_metadata_no_gated_checkpoint_download",
        "hidden_size": 2048,
        "intermediate_size": 8192,
        "num_attention_heads": 32,
        "num_key_value_heads": 8,
        "head_dim": 64,
        "decoder_layers": 16,
        "sequence_length": sequence_length,
        "batch_size": 1,
    }


def _metadata_from_hf_config(model_name: str, hf_config: Any, config: AgentConfig | None, source: str) -> dict[str, Any]:
    hidden_size = int(getattr(hf_config, "hidden_size"))
    intermediate_size = int(getattr(hf_config, "intermediate_size"))
    attention_heads = int(getattr(hf_config, "num_attention_heads"))
    kv_heads = int(getattr(hf_config, "num_key_value_heads", attention_heads))
    head_dim = int(getattr(hf_config, "head_dim", hidden_size // attention_heads))
    sequence_length = int(getattr(hf_config, "max_position_embeddings", config.model.sequence_length if config else 2048))
    if config is not None:
        sequence_length = min(sequence_length, config.model.sequence_length)
    return {
        "name": model_name,
        "family": "llama_decoder_only_transformer",
        "target_checkpoint": model_name == "meta-llama/Llama-3.2-1B",
        "metadata_source": source,
        "model_type": getattr(hf_config, "model_type", None),
        "hidden_size": hidden_size,
        "intermediate_size": intermediate_size,
        "num_attention_heads": attention_heads,
        "num_key_value_heads": kv_heads,
        "head_dim": head_dim,
        "decoder_layers": int(getattr(hf_config, "num_hidden_layers")),
        "sequence_length": sequence_length,
        "batch_size": 1,
    }


def resolve_llama_model_metadata(model_name: str, config: AgentConfig | None = None) -> dict[str, Any]:
    fallback = _fallback_llama32_1b_metadata(model_name, config)
    allow_download = os.environ.get("NL2HDL_ALLOW_HF_CONFIG_DOWNLOAD") == "1"
    try:
        from transformers import AutoConfig

        hf_config = AutoConfig.from_pretrained(model_name, local_files_only=not allow_download)
        if getattr(hf_config, "model_type", None) != "llama":
            fallback["metadata_resolution"] = {
                "status": "fallback",
                "reason": f"AutoConfig model_type {getattr(hf_config, 'model_type', None)!r} is not llama",
            }
            return fallback
        source = "huggingface_auto_config_download_enabled" if allow_download else "huggingface_auto_config_local_cache"
        metadata = _metadata_from_hf_config(model_name, hf_config, config, source)
        metadata["metadata_resolution"] = {"status": "resolved", "allow_download": allow_download}
        return metadata
    except Exception as exc:
        fallback["metadata_resolution"] = {
            "status": "fallback",
            "allow_download": allow_download,
            "reason": f"{type(exc).__name__}: {exc}",
        }
        return fallback


def _llama_projection_shapes(metadata: dict[str, Any]) -> dict[str, dict[str, int]]:
    hidden_size = int(metadata["hidden_size"])
    intermediate_size = int(metadata["intermediate_size"])
    kv_width = int(metadata["num_key_value_heads"]) * int(metadata["head_dim"])
    return {
        "q_proj": {"rows": hidden_size, "cols": hidden_size},
        "k_proj": {"rows": kv_width, "cols": hidden_size},
        "v_proj": {"rows": kv_width, "cols": hidden_size},
        "o_proj": {"rows": hidden_size, "cols": hidden_size},
        "gate_proj": {"rows": intermediate_size, "cols": hidden_size},
        "up_proj": {"rows": intermediate_size, "cols": hidden_size},
        "down_proj": {"rows": hidden_size, "cols": intermediate_size},
    }


def build_llama_semantic_graph(model_name: str, config: AgentConfig | None = None) -> dict[str, Any]:
    metadata = resolve_llama_model_metadata(model_name, config)
    projection_shapes = _llama_projection_shapes(metadata)
    memory_data_width = config.hardware.memory_data_width if config is not None else 128
    bytes_per_mem_word = memory_data_width // 8

    projection_memory: dict[str, Any] = {}
    packed_bytes_per_layer = 0
    for name, shape in projection_shapes.items():
        rows = int(shape["rows"])
        cols = int(shape["cols"])
        packed_bytes = (rows * cols * 4) // 8
        projection_memory[name] = {
            "rows": rows,
            "cols": cols,
            "packed_int4_bytes": packed_bytes,
            "memory_data_width_bits": memory_data_width,
            "memory_beats": math.ceil(packed_bytes / bytes_per_mem_word),
            "partition": "gemm",
            "weight_storage": "external_ddr_gptq_packed",
        }
        packed_bytes_per_layer += packed_bytes

    layer_template = [
        {"name": "input_layernorm", "op_type": "RMSNorm", "partition": "non_gemm", "tensor_shape": [metadata["hidden_size"]]},
        {"name": "q_proj", "op_type": "MatMul", "partition": "gemm", **projection_shapes["q_proj"]},
        {"name": "k_proj", "op_type": "MatMul", "partition": "gemm", **projection_shapes["k_proj"]},
        {"name": "v_proj", "op_type": "MatMul", "partition": "gemm", **projection_shapes["v_proj"]},
        {"name": "rope_qk", "op_type": "RoPE", "partition": "non_gemm", "head_dim": metadata["head_dim"]},
        {
            "name": "attention_scores_softmax_kv",
            "op_type": "AttentionControl",
            "partition": "non_gemm",
            "kv_cache": "external_or_streamed_target_required",
        },
        {"name": "o_proj", "op_type": "MatMul", "partition": "gemm", **projection_shapes["o_proj"]},
        {"name": "attention_residual", "op_type": "Add", "partition": "non_gemm", "tensor_shape": [metadata["hidden_size"]]},
        {"name": "post_attention_layernorm", "op_type": "RMSNorm", "partition": "non_gemm", "tensor_shape": [metadata["hidden_size"]]},
        {"name": "gate_proj", "op_type": "MatMul", "partition": "gemm", **projection_shapes["gate_proj"]},
        {"name": "up_proj", "op_type": "MatMul", "partition": "gemm", **projection_shapes["up_proj"]},
        {"name": "silu_gate", "op_type": "SiLU", "partition": "non_gemm", "tensor_shape": [metadata["intermediate_size"]]},
        {"name": "swiglu_multiply", "op_type": "Mul", "partition": "non_gemm", "tensor_shape": [metadata["intermediate_size"]]},
        {"name": "down_proj", "op_type": "MatMul", "partition": "gemm", **projection_shapes["down_proj"]},
        {"name": "mlp_residual", "op_type": "Add", "partition": "non_gemm", "tensor_shape": [metadata["hidden_size"]]},
    ]
    gemm_ops = [op["name"] for op in layer_template if op["partition"] == "gemm"]
    non_gemm_ops = [op["name"] for op in layer_template if op["partition"] == "non_gemm"]
    decoder_layers = int(metadata["decoder_layers"])
    return {
        "graph_kind": "llama_decoder_only_semantic_graph",
        "coverage_level": "target_model_semantic_inspect_no_checkpoint_weights",
        "model": metadata,
        "partition_strategy": "gemm_non_gemm",
        "partition": {
            "gemm": gemm_ops,
            "non_gemm": non_gemm_ops,
        },
        "decoder_layer_template": layer_template,
        "projection_shapes": projection_shapes,
        "projection_memory_estimates": projection_memory,
        "model_memory_estimate": {
            "packed_int4_bytes_per_decoder_layer": packed_bytes_per_layer,
            "packed_int4_bytes_all_decoder_layers": packed_bytes_per_layer * decoder_layers,
            "memory_data_width_bits": memory_data_width,
            "excludes_embeddings_lm_head_and_gptq_metadata": True,
        },
        "gptq_metadata_requirements": {
            "quantization": config.optimization.quantization if config is not None else "int4_gptq",
            "checkpoint_metadata_required": ["group_size", "scales", "zero_points", "packing_order"],
            "fixture_group_size_used_by_existing_projection_fixtures": 4,
            "target_group_size": "read_from_checkpoint_or_config_when_available",
            "packed_weight_order": "little_nibble_order_element_idx_is_idx_times_4",
        },
        "next_hdl_contract_inputs": {
            "projection_kernel_names": gemm_ops,
            "non_gemm_kernel_names": non_gemm_ops,
            "token_loop_child_fixture": "token_loop_decoder_block_fixture",
            "must_not_claim_full_llama_execution": True,
        },
    }


def _first_tensor_summary_for_kind(projection: dict[str, Any] | None, kind: str) -> dict[str, Any] | None:
    if projection is None:
        return None
    summaries = projection.get("tensor_summaries", {})
    if not isinstance(summaries, dict):
        return None
    keys = projection.get("keys", {})
    if isinstance(keys, dict):
        for key in keys.get(kind, []):
            summary = summaries.get(key)
            if isinstance(summary, dict):
                result = dict(summary)
                result.setdefault("key", key)
                return result
    suffix = f".{kind}"
    for key, summary in summaries.items():
        if isinstance(key, str) and key.endswith(suffix) and isinstance(summary, dict):
            result = dict(summary)
            result.setdefault("key", key)
            return result
    return None


def _shape_matches(observed: Any, expected: list[int]) -> bool:
    if not isinstance(observed, list) or len(observed) != len(expected):
        return False
    return all(isinstance(value, int) and value == expected[idx] for idx, value in enumerate(observed))


def _dtype_in(summary: dict[str, Any] | None, accepted: set[str]) -> bool:
    if summary is None:
        return False
    dtype = summary.get("dtype")
    return isinstance(dtype, str) and dtype.upper() in accepted


def _dtype_size_bytes(dtype: Any) -> int | None:
    if not isinstance(dtype, str):
        return None
    return {
        "I8": 1,
        "U8": 1,
        "I16": 2,
        "U16": 2,
        "F16": 2,
        "BF16": 2,
        "I32": 4,
        "U32": 4,
        "F32": 4,
    }.get(dtype.upper())


def _byte_count_matches(summary: dict[str, Any] | None, expected_shape: list[int]) -> bool:
    if summary is None:
        return False
    dtype_size = _dtype_size_bytes(summary.get("dtype"))
    byte_count = summary.get("byte_count")
    if dtype_size is None or not isinstance(byte_count, int):
        return False
    expected_count = dtype_size
    for dim in expected_shape:
        expected_count *= dim
    return byte_count == expected_count


def _gptq_projection_layout_expectation(rows: int, cols: int, bits: int | None, group_size: int | None) -> dict[str, Any]:
    values_per_i32 = 32 // bits if isinstance(bits, int) and bits > 0 and 32 % bits == 0 else None
    groups = math.ceil(cols / group_size) if isinstance(group_size, int) and group_size > 0 else None
    qweight_shape = (
        [math.ceil(cols / values_per_i32), rows]
        if isinstance(values_per_i32, int)
        else None
    )
    qzeros_shape = (
        [groups, math.ceil(rows / values_per_i32)]
        if isinstance(groups, int) and isinstance(values_per_i32, int)
        else None
    )
    scales_shape = [groups, rows] if isinstance(groups, int) else None
    return {
        "format": "auto_gptq_int32_packed_int4_header",
        "bits": bits,
        "group_size": group_size,
        "values_per_i32": values_per_i32,
        "group_count": groups,
        "qweight_dtype": "I32",
        "qweight_shape": qweight_shape,
        "qzeros_dtype": "I32",
        "qzeros_shape": qzeros_shape,
        "scales_dtype": "F16|BF16|F32",
        "scales_shape": scales_shape,
    }


def build_gptq_weight_layout_preflight(
    semantic_graph: dict[str, Any],
    gptq_metadata: dict[str, Any] | None,
) -> dict[str, Any]:
    projection_shapes = semantic_graph["projection_shapes"]
    projection_metadata = gptq_metadata.get("projection_metadata", []) if gptq_metadata is not None else []
    if not isinstance(projection_metadata, list):
        projection_metadata = []
    metadata_by_name = {
        item["name"]: item
        for item in projection_metadata
        if isinstance(item, dict) and isinstance(item.get("name"), str)
    }
    bits = gptq_metadata.get("bits") if gptq_metadata is not None else None
    group_size = gptq_metadata.get("group_size") if gptq_metadata is not None else None
    bits_compatible = bits == 4
    group_size_compatible = isinstance(group_size, int) and group_size > 0

    checks = []
    compatible_count = 0
    for name in semantic_graph["partition"]["gemm"]:
        shape = projection_shapes[name]
        rows = int(shape["rows"])
        cols = int(shape["cols"])
        expected_qweight_bytes = math.ceil(rows * cols / 2)
        layout_expectation = _gptq_projection_layout_expectation(rows, cols, bits, group_size)
        projection = metadata_by_name.get(name)
        qweight_summary = _first_tensor_summary_for_kind(projection, "qweight")
        qzeros_summary = _first_tensor_summary_for_kind(projection, "qzeros")
        scales_summary = _first_tensor_summary_for_kind(projection, "scales")
        has_complete_keys = bool(
            projection
            and projection.get("has_qweight")
            and projection.get("has_qzeros")
            and projection.get("has_scales")
        )
        qweight_byte_count = qweight_summary.get("byte_count") if qweight_summary is not None else None
        qweight_byte_count_matches = qweight_byte_count == expected_qweight_bytes
        header_summaries_available = all(
            summary is not None for summary in (qweight_summary, qzeros_summary, scales_summary)
        )
        qweight_shape_matches = (
            _shape_matches(qweight_summary.get("shape") if qweight_summary is not None else None, layout_expectation["qweight_shape"])
            if isinstance(layout_expectation["qweight_shape"], list)
            else False
        )
        qzeros_shape_matches = (
            _shape_matches(qzeros_summary.get("shape") if qzeros_summary is not None else None, layout_expectation["qzeros_shape"])
            if isinstance(layout_expectation["qzeros_shape"], list)
            else False
        )
        scales_shape_matches = (
            _shape_matches(scales_summary.get("shape") if scales_summary is not None else None, layout_expectation["scales_shape"])
            if isinstance(layout_expectation["scales_shape"], list)
            else False
        )
        qweight_dtype_matches = _dtype_in(qweight_summary, {"I32"})
        qzeros_dtype_matches = _dtype_in(qzeros_summary, {"I32"})
        scales_dtype_matches = _dtype_in(scales_summary, {"F16", "BF16", "F32"})
        qzeros_byte_count_matches = (
            _byte_count_matches(qzeros_summary, layout_expectation["qzeros_shape"])
            if isinstance(layout_expectation["qzeros_shape"], list)
            else False
        )
        scales_byte_count_matches = (
            _byte_count_matches(scales_summary, layout_expectation["scales_shape"])
            if isinstance(layout_expectation["scales_shape"], list)
            else False
        )
        target_layout_compatible = (
            bits_compatible
            and group_size_compatible
            and has_complete_keys
            and header_summaries_available
            and qweight_byte_count_matches
            and qweight_dtype_matches
            and qweight_shape_matches
            and qzeros_dtype_matches
            and qzeros_shape_matches
            and qzeros_byte_count_matches
            and scales_dtype_matches
            and scales_shape_matches
            and scales_byte_count_matches
        )
        if target_layout_compatible:
            compatible_count += 1
        if not bits_compatible:
            status = "unsupported_or_missing_gptq_bits"
        elif not group_size_compatible:
            status = "missing_or_invalid_gptq_group_size"
        elif projection is None:
            status = "missing_projection_metadata"
        elif not has_complete_keys:
            status = "missing_complete_qweight_qzeros_scales_keys"
        elif not header_summaries_available:
            status = "missing_header_tensor_summaries"
        elif not qweight_byte_count_matches:
            status = "qweight_byte_count_mismatch"
        elif not qweight_dtype_matches or not qzeros_dtype_matches or not scales_dtype_matches:
            status = "tensor_dtype_mismatch"
        elif not qweight_shape_matches:
            status = "qweight_packed_shape_mismatch"
        elif not qzeros_shape_matches or not scales_shape_matches:
            status = "groupwise_metadata_shape_mismatch"
        elif not qzeros_byte_count_matches or not scales_byte_count_matches:
            status = "groupwise_metadata_byte_count_mismatch"
        else:
            status = "target_layout_compatible"
        checks.append(
            {
                "name": name,
                "expected_rows": rows,
                "expected_cols": cols,
                "expected_qweight_int4_packed_bytes": expected_qweight_bytes,
                "layout_expectation": layout_expectation,
                "has_complete_qweight_qzeros_scales_keys": has_complete_keys,
                "header_summaries_available": header_summaries_available,
                "qweight": qweight_summary,
                "qzeros": qzeros_summary,
                "scales": scales_summary,
                "qweight_byte_count_matches_expected": qweight_byte_count_matches,
                "qweight_dtype_matches_expected": qweight_dtype_matches,
                "qweight_shape_matches_expected": qweight_shape_matches,
                "qzeros_dtype_matches_expected": qzeros_dtype_matches,
                "qzeros_shape_matches_expected": qzeros_shape_matches,
                "qzeros_byte_count_matches_expected": qzeros_byte_count_matches,
                "scales_dtype_matches_expected": scales_dtype_matches,
                "scales_shape_matches_expected": scales_shape_matches,
                "scales_byte_count_matches_expected": scales_byte_count_matches,
                "target_layout_compatible": target_layout_compatible,
                "status": status,
            }
        )

    required_count = len(semantic_graph["partition"]["gemm"])
    passed = compatible_count == required_count
    return {
        "artifact": "gptq_weight_layout_preflight",
        "status": "passed" if passed else "blocked",
        "source": "safetensors_header_tensor_summaries",
        "required_quantization": "gptq_int4",
        "bits_compatible": bits_compatible,
        "group_size": group_size,
        "group_size_compatible": group_size_compatible,
        "target_compatible_projection_count": compatible_count,
        "required_projection_count": required_count,
        "checks": checks,
        "blocking_reason": None
        if passed
        else "target GPTQ projection headers must provide INT4 qweight byte counts, AutoGPTQ packed qweight shape/dtype, and groupwise qzeros/scales shape/dtype metadata matching semantic projection shapes",
        "does_not_claim": [
            "checkpoint_tensor_payload_loading",
            "numeric_GPTQ_correctness",
            "checkpoint_specific_qweight_order_correctness",
            "full_LLaMA_model_execution",
        ],
    }


def _checkpoint_tensor_source(summary: dict[str, Any] | None) -> dict[str, Any] | None:
    if summary is None:
        return None
    return {
        "file": summary.get("file"),
        "key": summary.get("key"),
        "dtype": summary.get("dtype"),
        "shape": summary.get("shape"),
        "data_offsets": summary.get("data_offsets"),
        "byte_count": summary.get("byte_count"),
        "metadata_status": summary.get("metadata_status"),
    }


def _target_weight_stream_plan(
    check: dict[str, Any],
    projection_memory: dict[str, Any],
    memory_data_width_bits: int,
) -> dict[str, Any]:
    qweight = _checkpoint_tensor_source(check.get("qweight"))
    bytes_per_beat = memory_data_width_bits // 8
    data_offsets = qweight.get("data_offsets") if qweight is not None else None
    byte_count = qweight.get("byte_count") if qweight is not None else None
    byte_offset = data_offsets[0] if isinstance(data_offsets, list) and len(data_offsets) == 2 else None
    byte_end_exclusive = byte_offset + byte_count if isinstance(byte_offset, int) and isinstance(byte_count, int) else None
    request_beat_start = byte_offset // bytes_per_beat if isinstance(byte_offset, int) else None
    request_byte_addr = request_beat_start * bytes_per_beat if isinstance(request_beat_start, int) else None
    request_beat_end = (
        math.ceil(byte_end_exclusive / bytes_per_beat) if isinstance(byte_end_exclusive, int) else None
    )
    request_beat_count = (
        request_beat_end - request_beat_start
        if isinstance(request_beat_end, int) and isinstance(request_beat_start, int)
        else None
    )
    first_beat_byte_offset = (
        byte_offset - request_byte_addr if isinstance(byte_offset, int) and isinstance(request_byte_addr, int) else None
    )
    last_beat_valid_bytes = (
        byte_end_exclusive - ((request_beat_end - 1) * bytes_per_beat)
        if isinstance(byte_end_exclusive, int) and isinstance(request_beat_end, int) and request_beat_count
        else None
    )
    observed_memory_beats = math.ceil(byte_count / bytes_per_beat) if isinstance(byte_count, int) else None
    return {
        "source": "checkpoint_safetensors_header" if qweight is not None else "unavailable",
        "qweight_file": qweight.get("file") if qweight is not None else None,
        "qweight_key": qweight.get("key") if qweight is not None else None,
        "qweight_byte_offset": byte_offset,
        "qweight_byte_end_exclusive": byte_end_exclusive,
        "qweight_byte_count": byte_count,
        "memory_data_width_bits": memory_data_width_bits,
        "bytes_per_memory_beat": bytes_per_beat,
        "raw_qweight_memory_beats": projection_memory["memory_beats"],
        "observed_memory_beats": observed_memory_beats,
        "request_byte_addr": request_byte_addr,
        "request_beat_start_index": request_beat_start,
        "request_beat_count": request_beat_count,
        "first_beat_byte_offset": first_beat_byte_offset,
        "last_beat_valid_bytes": last_beat_valid_bytes,
        "request_covers_unaligned_qweight_range": bool(
            isinstance(request_byte_addr, int)
            and isinstance(request_beat_count, int)
            and isinstance(byte_offset, int)
            and isinstance(byte_end_exclusive, int)
            and request_byte_addr <= byte_offset
            and request_byte_addr + request_beat_count * bytes_per_beat >= byte_end_exclusive
        ),
        "stream_plan_valid": bool(check.get("target_layout_compatible"))
        and isinstance(byte_count, int)
        and observed_memory_beats == projection_memory["memory_beats"]
        and isinstance(request_beat_count, int)
        and request_beat_count >= observed_memory_beats,
        "does_not_claim": [
            "checkpoint_tensor_payload_loading",
            "AXI_or_DDR_burst_execution",
            "checkpoint_specific_qweight_order_correctness",
        ],
    }


def _payload_words_stream_preview(
    words32_le_hex: list[str],
    memory_data_width_bits: int,
    sample_byte_count: int | None,
) -> dict[str, Any]:
    words_per_beat = memory_data_width_bits // 32 if memory_data_width_bits > 0 else 0
    bytes_per_beat = memory_data_width_bits // 8 if memory_data_width_bits > 0 else 0
    full_beats = len(words32_le_hex) // words_per_beat if words_per_beat else 0
    beat_chunks = [
        words32_le_hex[idx : idx + words_per_beat]
        for idx in range(0, full_beats * words_per_beat, words_per_beat)
    ]
    beat_hex = []
    for chunk in beat_chunks:
        values = [int(word, 16) for word in chunk]
        beat_hex.append("0x" + "".join(f"{value:08x}" for value in reversed(values)))
    return {
        "source": "gptq_payload_probe.qweight_payload_words32_le_hex",
        "payload_order": "safetensors_payload_prefix_32bit_little_endian_words",
        "memory_data_width_bits": memory_data_width_bits,
        "bytes_per_memory_beat": bytes_per_beat,
        "words32_per_memory_beat": words_per_beat,
        "sample_byte_count": sample_byte_count,
        "sampled_full_memory_beat_count": full_beats,
        "covers_first_memory_beat": full_beats >= 1,
        "first_memory_beats_128b_le_hex": beat_hex if memory_data_width_bits == 128 else [],
        "memory_beat_word_chunks32_le_hex": beat_chunks,
        "does_not_claim": [
            "full_qweight_payload_streaming",
            "AXI_or_DDR_burst_execution",
            "checkpoint_specific_qweight_order_correctness",
        ],
    }


