        "full_sequence_length_KV_cache",
        "multi_head_attention",
        "grouped_query_attention",
        "true_exponential_softmax",
        "DDR_AXI_KV_cache_movement",
        "residual_add_scheduling",
        "MLP_SwiGLU_path",
        "full_token_prefill_decode_loop",
        "full_decoder_block",
        "full_LLaMA_model_execution",
