def _emit_layer_fsm_fixture(
    out_dir: Path,
    requested_pe_lanes: int,
    memory_data_width: int,
) -> tuple[list[Path], dict[str, Any], dict[str, Any]]:
    child_files, _, child_extra = _emit_decoder_child_datapath(
        out_dir,
        requested_pe_lanes=requested_pe_lanes,
        memory_data_width=memory_data_width,
    )

    expected_outputs = child_extra["expected_outputs"]
    expected_child_trace = child_extra["expected_child_trace"]
    expected_layer_trace = "0x4241"
    fsm_state_order = ["IDLE", "CHILD_START", "CHILD_BUSY", "DONE"]
    child_start_done_trace = ["decoder_child_datapath_start", "decoder_child_datapath_done"]
    child_modules = [
        {
            "name": "decoder_child_datapath",
            "coverage_level": "decoder_child_datapath_fixture",
            "instantiated": True,
            "input_source": "static_decoder_child_fixture_inputs",
            "output_consumed_by": "layer_fsm_fixture_output_o",
        }
    ]
    omitted_operations = [
        "multi-layer iteration",
        "token prefill/decode loop",
        "DDR packed-weight streaming",
        "KV-cache movement",
        "attention and softmax",
        "residual paths",
        "MLP",
        "final output layer",
        "full Top FSM scheduling",
    ]
    numeric_policy: dict[str, Any] = {
        "fixture_kind": "layer_fsm_fixture",
        "datapath_composition": "instantiated_decoder_child_datapath_fixture",
        "child_sequence": "decoder_child_datapath",
        "full_decoder_block": False,
        "full_attention": False,
        "full_token_scheduling": False,
        "full_top_fsm": False,
        "full_llama_coverage": False,
    }
    golden_report = {
        "coverage_level": "layer_fsm_fixture",
        "child_modules": child_modules,
        "fsm_state_order": fsm_state_order,
        "child_start_done_trace": child_start_done_trace,
        "expected_layer_trace_hex": expected_layer_trace,
        "expected_child_trace_hex": expected_child_trace,
        "expected_outputs_raw_q13_4": expected_outputs,
        "omitted_operations": omitted_operations,
        "numeric_policy": numeric_policy,
    }
    (out_dir / "layer_fsm_fixture_golden.json").write_text(
        json.dumps(golden_report, indent=2),
        encoding="utf-8",
    )

    sv = out_dir / "layer_fsm_fixture.sv"
    tb = out_dir / "tb_layer_fsm_fixture.sv"
    sv.write_text(_layer_fsm_fixture_sv(), encoding="utf-8")
    tb.write_text(_layer_fsm_fixture_tb(expected_outputs), encoding="utf-8")

    child_rtl_files = [path for path in child_files if not path.name.startswith("tb_")]
    extra_report: dict[str, Any] = {
        "child_modules": child_modules,
        "fsm_state_order": fsm_state_order,
        "child_start_done_trace": child_start_done_trace,
        "expected_layer_trace": expected_layer_trace,
        "expected_child_trace": expected_child_trace,
        "expected_outputs": expected_outputs,
        "omitted_operations": omitted_operations,
        "layer_fsm_fixture": True,
        "datapath_child_instantiation": True,
        "does_not_claim": [
            "top_fsm",
            "full_token_scheduling",
            "full_decoder_block",
            "full_attention",
            "full_kv_cache",
            "full_mlp",
            "full_llama_coverage",
        ],
        "golden_reference": "layer_fsm_fixture_golden.json",
    }
    return [*child_rtl_files, sv, tb], numeric_policy, extra_report


def _parse_layer_start_done_trace(output: str) -> dict[str, Any]:
    marker = "LAYER_TRACE layer_fsm_fixture "
    for line in output.splitlines():
        if marker in line:
            return {
                "recorded": True,
                "line": line.strip(),
                "layer_trace_hex": line.strip().split("layer_trace_hex=", 1)[-1].split()[0],
                "child_trace_hex": line.strip().split("child_trace_hex=", 1)[-1].split()[0],
            }
    return {"recorded": False, "line": None, "layer_trace_hex": None, "child_trace_hex": None}


def _parse_layer_fsm_attention_fixture_sim_trace(output: str) -> dict[str, Any]:
    parsed: dict[str, Any] = {}
    layer_match = re.search(
        r"LAYER_ATTENTION_TRACE layer_fsm_attention_fixture layer_trace_hex=(0x[0-9a-fA-F]+) child_trace_hex=(0x[0-9a-fA-F]+) events=([a-zA-Z0-9_,]+)",
        output,
    )
    if layer_match:
        parsed["simulation_layer_start_done_trace"] = {
            "recorded": True,
            "layer_trace_hex": layer_match.group(1),
            "child_trace_hex": layer_match.group(2),
            "ordered_events": layer_match.group(3).split(","),
            "evidence_source": "parsed_from_iverilog_layer_fsm_attention_trace",
        }
        parsed["observed_layer_start_done_trace"] = layer_match.group(3).split(",")
    else:
        parsed["simulation_layer_start_done_trace"] = {
            "recorded": False,
            "layer_trace_hex": None,
            "child_trace_hex": None,
            "ordered_events": [],
            "evidence_source": "parsed_from_iverilog_layer_fsm_attention_trace",
        }
    child_match = re.search(
        r"CHILD_TRACE layer_fsm_attention_fixture trace_hex=(0x[0-9a-fA-F]+) events=([a-zA-Z0-9_,]+)",
        output,
    )
    if child_match:
        parsed["child_datapath_trace"] = {
            "recorded": True,
            "trace_hex": child_match.group(1),
            "ordered_events": child_match.group(2).split(","),
            "evidence_source": "parsed_from_layer_fsm_integration_testbench_child_status",
        }
        parsed["simulation_child_start_done_trace"] = parsed["child_datapath_trace"]
    rms_match = re.search(
        r"RMS_LOOKUP_TRACE layer_fsm_attention_fixture selector=(\d+) valid=(\d+) inv_rms=(\d+) sumsq=(\d+)",
        output,
    )
    source_summary: dict[str, Any] = {
        "evidence_source": "parsed_from_layer_fsm_integration_testbench_hierarchical_child_signals"
    }
    if rms_match:
        source_summary["rmsnorm_lookup_trace"] = {
            "selector": int(rms_match.group(1)),
            "valid": bool(int(rms_match.group(2))),
            "inv_rms": int(rms_match.group(3)),
            "sumsq": int(rms_match.group(4)),
        }
    rope_entries: list[dict[str, Any]] = []
    for match in re.finditer(
        r"ROPE_LOOKUP_TRACE layer_fsm_attention_fixture position=(\d+) pair=(\d+) valid=(\d+) cos=(-?\d+) sin=(-?\d+)",
        output,
    ):
        rope_entries.append(
            {
                "position": int(match.group(1)),
                "pair_index": int(match.group(2)),
                "valid": bool(int(match.group(3))),
                "cos": int(match.group(4)),
                "sin": int(match.group(5)),
            }
        )
    if rope_entries:
        source_summary["rope_lookup_trace"] = rope_entries
    if len(source_summary) > 1:
        parsed["source_path_evidence_summary"] = source_summary
    projection_summary: dict[str, Any] = {
        "evidence_source": "parsed_from_layer_fsm_integration_testbench_hierarchical_child_signals"
    }
    projection_match = re.search(
        r"PROJECTION_OUTPUT_TRACE layer_fsm_attention_fixture output=(-?\d+),(-?\d+) shell_status=(0x[0-9a-fA-F]+)",
        output,
    )
    if projection_match:
        projection_summary["projection_output_vector"] = [
            int(projection_match.group(1)),
            int(projection_match.group(2)),
        ]
        projection_summary["shell_status_hex"] = projection_match.group(3)
    projection_stream_match = re.search(
        r"PROJECTION_STREAM_TRACE layer_fsm_attention_fixture shell_status=(0x[0-9a-fA-F]+) request_accepted=(\d+) response_count=(\d+) response_mask=(0x[0-9a-fA-F]+) payload_emit_count=(\d+) projection_consume_count=(\d+) payload_match=(\d+) source=([a-zA-Z0-9_]+)",
        output,
    )
    if projection_stream_match:
        projection_summary["stream_status"] = {
            "shell_status_hex": projection_stream_match.group(1),
            "request_accepted": bool(int(projection_stream_match.group(2))),
            "response_count": int(projection_stream_match.group(3)),
            "response_mask_hex": projection_stream_match.group(4),
            "payload_emit_count": int(projection_stream_match.group(5)),
            "projection_consume_count": int(projection_stream_match.group(6)),
            "payload_match": bool(int(projection_stream_match.group(7))),
            "raw_source_label": projection_stream_match.group(8),
        }
    if len(projection_summary) > 1:
        parsed["projection_shell_evidence_summary"] = projection_summary
    attention_summary: dict[str, Any] = {
        "evidence_source": "parsed_from_layer_fsm_integration_testbench_hierarchical_child_signals"
    }
    write_match = re.search(
        r"CACHE_WRITE_TRACE layer_fsm_attention_fixture count=(\d+) slot=(\d+) key=([-,\d]+) value=([-,\d]+) stable=(\d+)",
        output,
    )
    if write_match:
        attention_summary["cache_write_trace"] = {
            "count": int(write_match.group(1)),
            "slot": int(write_match.group(2)),
            "key": _parse_attention_vector(write_match.group(3)),
            "value": _parse_attention_vector(write_match.group(4)),
            "field_stability_checked": bool(int(write_match.group(5))),
        }
    key_read_match = re.search(
        r"KEY_READ_TRACE layer_fsm_attention_fixture slots=(\d+),(\d+) keys=([-,\d]+)\|([-,\d]+)",
        output,
    )
    if key_read_match:
        attention_summary["key_read_trace"] = [
            {"slot": int(key_read_match.group(1)), "key": _parse_attention_vector(key_read_match.group(3))},
            {"slot": int(key_read_match.group(2)), "key": _parse_attention_vector(key_read_match.group(4))},
        ]
    value_read_match = re.search(
        r"VALUE_READ_TRACE layer_fsm_attention_fixture slots=(\d+),(\d+) values=([-,\d]+)\|([-,\d]+)",
        output,
    )
    if value_read_match:
        attention_summary["value_read_trace"] = [
            {"slot": int(value_read_match.group(1)), "value": _parse_attention_vector(value_read_match.group(3))},
            {"slot": int(value_read_match.group(2)), "value": _parse_attention_vector(value_read_match.group(4))},
        ]
    score_match = re.search(r"SCORE_TRACE layer_fsm_attention_fixture scores=(-?\d+),(-?\d+)", output)
    if score_match:
        attention_summary["attention_score_trace"] = [int(score_match.group(1)), int(score_match.group(2))]
    control_match = re.search(
        r"SOFTMAX_CONTROL_TRACE layer_fsm_attention_fixture policy=([a-zA-Z0-9_]+) weights=(-?\d+),(-?\d+) exp=(\d+)",
        output,
    )
    if control_match:
        attention_summary["softmax_control_trace"] = {
            "policy": control_match.group(1),
            "weights": [int(control_match.group(2)), int(control_match.group(3))],
            "softmax_exp_in_rtl": bool(int(control_match.group(4))),
        }
    attention_output_match = re.search(
        r"ATTENTION_OUTPUT_TRACE layer_fsm_attention_fixture output=([-,\d]+)", output
    )
    if attention_output_match:
        attention_summary["attention_output_vector"] = _parse_attention_vector(attention_output_match.group(1))
    if len(attention_summary) > 1:
        parsed["attention_kv_evidence_summary"] = attention_summary
    final_match = re.search(
        r"FINAL_OUTPUT_TRACE layer_fsm_attention_fixture output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if final_match:
        parsed["observed_final_fixture_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_compact_status_hex"] = final_match.group(2)
    stable_match = re.search(r"TOP_STABILITY_TRACE layer_fsm_attention_fixture stable=(\d+)", output)
    if stable_match:
        parsed["top_done_stability_observed"] = bool(int(stable_match.group(1)))
    hold_match = re.search(
        r"CHILD_START_HOLD_TRACE layer_fsm_attention_fixture busy_cycles=(\d+) done_seen_while_start_high=(\d+) deasserted_after_done=(\d+)",
        output,
    )
    if hold_match:
        parsed["child_start_hold_protocol_observed"] = {
            "busy_cycles": int(hold_match.group(1)),
            "done_seen_while_start_high": bool(int(hold_match.group(2))),
            "deasserted_after_done": bool(int(hold_match.group(3))),
            "evidence_source": "parsed_from_layer_fsm_testbench_child_start_monitor",
        }
    compact_match = re.search(
        r"COMPACT_IO_TRACE layer_fsm_attention_fixture estimated_iob_bits=(\d+) exposed_128b=(\d+) exposed_kv_arrays=(\d+) exposed_debug_arrays=(\d+)",
        output,
    )
    if compact_match:
        parsed["compact_io_observed_trace"] = {
            "estimated_iob_bits": int(compact_match.group(1)),
            "exposes_128b_memory_response": bool(int(compact_match.group(2))),
            "exposes_full_kv_arrays": bool(int(compact_match.group(3))),
            "exposes_full_debug_arrays": bool(int(compact_match.group(4))),
            "evidence_source": "parsed_from_layer_fsm_testbench_compact_io_trace",
        }
    return parsed


