def _layer_fsm_axi_attention_fixture_sv() -> str:
    sv = (
        _layer_fsm_attention_fixture_sv()
        .replace("layer_fsm_attention_fixture", "layer_fsm_axi_attention_fixture")
        .replace("decoder_child_attention_datapath", "decoder_child_axi_attention_datapath")
    )
    sv = sv.replace(
        """        CHILD_DONE  = 3'd3,
        DONE        = 3'd4""",
        """        CHILD_RELEASE = 3'd3,
        DONE          = 3'd4""",
    )
    sv = sv.replace("state_r <= CHILD_DONE;", "state_r <= CHILD_RELEASE;")
    sv = sv.replace(
        """                CHILD_DONE: begin
                    done_r <= 1'b1;
                    state_r <= DONE;
                end""",
        """                CHILD_RELEASE: begin
                    if (!child_done_w) begin
                        done_r <= 1'b1;
                        state_r <= DONE;
                    end
                end""",
    )
    return sv


def _layer_fsm_axi_attention_fixture_tb(
    expected_outputs: list[int],
    projection_payload_words: list[int] | None = None,
    projection_fixture_values: list[int] | None = None,
    projection_output_vector: list[int] | None = None,
) -> str:
    tb = _decoder_child_axi_attention_datapath_tb(
        expected_outputs,
        projection_payload_words=projection_payload_words,
        projection_fixture_values=projection_fixture_values,
        projection_output_vector=projection_output_vector,
    )
    replacements = {
        "tb_decoder_child_axi_attention_datapath": "tb_layer_fsm_axi_attention_fixture",
        "decoder_child_axi_attention_datapath dut (": "layer_fsm_axi_attention_fixture dut (",
        "decoder_child_axi_attention_datapath": "layer_fsm_axi_attention_fixture",
        "logic [95:0] status_vec;": "logic [111:0] status_vec;",
        "logic [95:0] stable_status_snapshot;": "logic [111:0] stable_status_snapshot;",
        "status_vec[47:0]": "status_vec[16 +: 48]",
        "status_vec[79:72]": "status_vec[88 +: 8]",
        "status_vec[63:60]": "status_vec[76 +: 4]",
        "parent_mask=0x00000000f000000000000000 parent_bit_lsb=60 parent_bit_msb=63": (
            "parent_mask=0x00000000f0000000000000000000 parent_bit_lsb=76 parent_bit_msb=79"
        ),
        "source=projection_axi_stream_integration.integration_status_o[45:42]": (
            "source=decoder_child_axi_attention_datapath.status_o[63:60]:projection_axi_stream_integration.integration_status_o[45:42]"
        ),
        "COMPACT_IO_TRACE layer_fsm_axi_attention_fixture estimated_iob_bits=164": (
            "COMPACT_IO_TRACE layer_fsm_axi_attention_fixture estimated_iob_bits=180"
        ),
    }
    for old, new in replacements.items():
        tb = tb.replace(old, new)
    for path in (
        "dut.u_projection_axi_stream_integration",
        "dut.u_k_projection_axi_stream_integration",
        "dut.u_v_projection_axi_stream_integration",
        "dut.u_o_projection_axi_stream_integration",
        "dut.u_rmsnorm_rope_source_path",
        "dut.u_attention_kv_cache_fixture",
    ):
        tb = tb.replace(path, path.replace("dut.", "dut.u_decoder_child_axi_attention_datapath."))

    tb = tb.replace(
        "    integer observed;\n",
        """    integer observed;
    logic child_busy_seen_r;
    logic child_done_seen_while_start_high_r;
    logic child_start_deasserted_after_done_r;
    logic child_done_release_seen_after_start_deassert_r;
    logic child_done_prev_r;
    integer child_busy_cycles;
""",
    )
    tb = tb.replace(
        "    always @(negedge aclk) begin\n",
        """    always @(posedge aclk) begin
        if (!aresetn) begin
            child_busy_seen_r <= 1'b0;
            child_done_seen_while_start_high_r <= 1'b0;
            child_start_deasserted_after_done_r <= 1'b0;
            child_done_release_seen_after_start_deassert_r <= 1'b0;
            child_done_prev_r <= 1'b0;
            child_busy_cycles <= 0;
        end else begin
            if (dut.child_start_r && !dut.child_done_w) begin
                child_busy_seen_r <= 1'b1;
                child_busy_cycles <= child_busy_cycles + 1;
            end
            if (child_busy_seen_r && !child_done_seen_while_start_high_r && !dut.child_done_w && !dut.child_start_r) begin
                $display("FAIL layer_fsm_axi_attention_fixture child start was not held while child busy");
                $fatal;
            end
            if (dut.child_start_r && dut.child_done_w) begin
                child_done_seen_while_start_high_r <= 1'b1;
            end
            if (child_done_prev_r && !dut.child_start_r) begin
                child_start_deasserted_after_done_r <= 1'b1;
            end
            if (child_done_prev_r && dut.child_start_r) begin
                $display("FAIL layer_fsm_axi_attention_fixture child start was not deasserted after child done_o");
                $fatal;
            end
            if (child_start_deasserted_after_done_r && !dut.child_start_r && !dut.child_done_w) begin
                child_done_release_seen_after_start_deassert_r <= 1'b1;
            end
            child_done_prev_r <= dut.child_done_w;
        end
    end

    always @(negedge aclk) begin
""",
    )
    tb = tb.replace(
        """        if (dut.u_decoder_child_axi_attention_datapath.u_projection_axi_stream_integration.axi_araddr_w != 32'h00120000 ||""",
        """        if (!child_done_seen_while_start_high_r || !child_start_deasserted_after_done_r || !child_done_release_seen_after_start_deassert_r || child_busy_cycles == 0) begin
            $display("FAIL layer_fsm_axi_attention_fixture child start protocol busy_cycles=%0d done_seen_while_start_high=%0d deasserted_after_done=%0d child_done_release_seen_after_start_deassert=%0d", child_busy_cycles, child_done_seen_while_start_high_r, child_start_deasserted_after_done_r, child_done_release_seen_after_start_deassert_r);
            $fatal;
        end
        if (status_vec[76 +: 4] != dut.child_status_w[63:60] ||
            dut.child_status_w[63:60] != dut.u_decoder_child_axi_attention_datapath.u_projection_axi_stream_integration.integration_status_o[45:42]) begin
            $display("FAIL layer_fsm_axi_attention_fixture layer compact AXI metadata bits layer=0x%0h child=0x%0h nested=0x%0h status=0x%0h",
                     status_vec[76 +: 4], dut.child_status_w[63:60], dut.u_decoder_child_axi_attention_datapath.u_projection_axi_stream_integration.integration_status_o[45:42], status_vec);
            $fatal;
        end
        if (dut.u_decoder_child_axi_attention_datapath.u_projection_axi_stream_integration.axi_araddr_w != 32'h00120000 ||""",
    )
    tb = tb.replace(
        """        $display("CHILD_TRACE layer_fsm_axi_attention_fixture trace_hex=0x%0h events=source_path_start,source_path_done,projection_axi_start,projection_axi_done,attention_kv_start,attention_kv_done", status_vec[16 +: 48]);""",
        """        $display("LAYER_AXI_ATTENTION_TRACE layer_fsm_axi_attention_fixture layer_trace_hex=0x%0h child_trace_hex=0x%0h events=decoder_child_axi_attention_datapath_start,decoder_child_axi_attention_datapath_done", status_vec[15:0], status_vec[16 +: 48]);
        $display("CHILD_TRACE layer_fsm_axi_attention_fixture trace_hex=0x%0h events=source_path_start,source_path_done,projection_axi_start,projection_axi_done,attention_kv_start,attention_kv_done", status_vec[16 +: 48]);""",
    )
    tb = tb.replace(
        """        $display("COMPACT_IO_TRACE layer_fsm_axi_attention_fixture estimated_iob_bits=180 exposed_128b_axi_data=0 exposed_kv_arrays=0 exposed_axi_debug=0");""",
        """        $display("CHILD_START_HOLD_TRACE layer_fsm_axi_attention_fixture busy_cycles=%0d done_seen_while_start_high=%0d deasserted_after_done=%0d child_done_release_seen_after_start_deassert=%0d", child_busy_cycles, child_done_seen_while_start_high_r, child_start_deasserted_after_done_r, child_done_release_seen_after_start_deassert_r);
        $display("COMPACT_IO_TRACE layer_fsm_axi_attention_fixture estimated_iob_bits=180 exposed_128b_axi_data=0 exposed_kv_arrays=0 exposed_axi_debug=0");""",
    )
    return tb


def _parse_top_fsm_axi_attention_fixture_sim_trace(output: str) -> dict[str, Any]:
    parsed: dict[str, Any] = {}
    top_match = re.search(
        r"TOP_AXI_ATTENTION_TRACE top_fsm_axi_attention_fixture "
        r"top_trace_hex=(0x[0-9a-fA-F]+) layer_trace_hex=(0x[0-9a-fA-F]+) "
        r"child_trace_hex=(0x[0-9a-fA-F]+) events=([a-zA-Z0-9_,]+)",
        output,
    )
    if top_match:
        parsed["simulation_top_layer_start_done_trace"] = {
            "recorded": True,
            "top_trace_hex": top_match.group(1),
            "layer_trace_hex": top_match.group(2),
            "child_trace_hex": top_match.group(3),
            "ordered_events": top_match.group(4).split(","),
            "evidence_source": "parsed_from_top_fsm_axi_attention_trace",
        }
        parsed["observed_top_layer_start_done_trace"] = top_match.group(4).split(",")
    else:
        parsed["simulation_top_layer_start_done_trace"] = {
            "recorded": False,
            "top_trace_hex": None,
            "layer_trace_hex": None,
            "child_trace_hex": None,
            "ordered_events": [],
            "evidence_source": "parsed_from_top_fsm_axi_attention_trace",
        }

    layer_match = re.search(
        r"LAYER_AXI_ATTENTION_TRACE top_fsm_axi_attention_fixture "
        r"layer_trace_hex=(0x[0-9a-fA-F]+) child_trace_hex=(0x[0-9a-fA-F]+) "
        r"events=([a-zA-Z0-9_,]+)",
        output,
    )
    if layer_match:
        parsed["layer_fsm_trace"] = {
            "recorded": True,
            "layer_trace_hex": layer_match.group(1),
            "child_trace_hex": layer_match.group(2),
            "ordered_events": layer_match.group(3).split(","),
            "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_layer_status",
        }
        parsed["observed_layer_start_done_trace"] = layer_match.group(3).split(",")

    hold_match = re.search(
        r"LAYER_START_HOLD_TRACE top_fsm_axi_attention_fixture busy_cycles=(\d+) "
        r"done_seen_while_start_high=(\d+) deasserted_after_done=(\d+) "
        r"child_done_release_seen_after_start_deassert=(\d+)",
        output,
    )
    if hold_match:
        release_seen = bool(int(hold_match.group(4)))
        parsed["layer_child_start_hold_protocol_observed"] = {
            "busy_cycles": int(hold_match.group(1)),
            "done_seen_while_start_high": bool(int(hold_match.group(2))),
            "deasserted_after_done": bool(int(hold_match.group(3))),
            "child_done_release_seen_after_start_deassert": release_seen,
            "done_release_seen_after_start_deassert": release_seen,
            "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_layer_start_monitor",
        }
        parsed["child_done_release_seen_after_start_deassert"] = release_seen

    normalized = output.replace("top_fsm_axi_attention_fixture", "decoder_child_axi_attention_datapath")
    child_parsed = _parse_decoder_child_axi_attention_datapath_sim_trace(normalized)
    if "simulation_child_start_done_trace" in child_parsed:
        parsed["child_datapath_trace"] = {
            **child_parsed["simulation_child_start_done_trace"],
            "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_nested_decoder_status",
        }
    if "source_path_rmsnorm_observed_trace" in child_parsed or "source_path_rope_observed_trace" in child_parsed:
        parsed["source_path_evidence_summary"] = {
            "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_nested_child_signals",
            "rmsnorm_lookup_trace": child_parsed.get("source_path_rmsnorm_observed_trace"),
            "rope_lookup_trace": child_parsed.get("source_path_rope_observed_trace"),
        }
    if (
        "axi_projection_child_observed_command_trace" in child_parsed
        or "axi_projection_child_observed_r_metadata_trace" in child_parsed
        or "axi_projection_child_payload_trace" in child_parsed
    ):
        parsed["nested_axi_projection_evidence_summary"] = {
            "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_nested_child_signals",
            "command_trace": child_parsed.get("axi_projection_child_observed_command_trace"),
            "r_metadata_trace": child_parsed.get("axi_projection_child_observed_r_metadata_trace"),
            "payload_trace": child_parsed.get("axi_projection_child_payload_trace"),
            "backpressure_trace": child_parsed.get("axi_projection_child_backpressure_trace"),
            "output_trace": child_parsed.get("axi_projection_child_observed_output_trace"),
            "round_trip_evidence": child_parsed.get("axi_projection_child_round_trip_evidence"),
            "projection_children": child_parsed.get("axi_projection_children_observed"),
        }
    if (
        "attention_kv_observed_write_trace" in child_parsed
        or "attention_kv_observed_key_read_trace" in child_parsed
        or "attention_kv_observed_score_trace" in child_parsed
    ):
        parsed["nested_attention_kv_evidence_summary"] = {
            "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_nested_child_signals",
            "cache_write_trace": child_parsed.get("attention_kv_observed_write_trace"),
            "key_read_trace": child_parsed.get("attention_kv_observed_key_read_trace"),
            "value_read_trace": child_parsed.get("attention_kv_observed_value_read_trace"),
            "attention_score_trace": child_parsed.get("attention_kv_observed_score_trace"),
            "softmax_control_trace": child_parsed.get("attention_kv_observed_softmax_control_trace"),
        }
    if "observed_final_fixture_output_vector" in child_parsed:
        parsed["observed_final_fixture_output_vector"] = child_parsed["observed_final_fixture_output_vector"]
    if "top_done_stability_observed" in child_parsed:
        parsed["top_done_stability_observed"] = child_parsed["top_done_stability_observed"]
    if "compact_io_observed_trace" in child_parsed:
        parsed["compact_io_observed_trace"] = child_parsed["compact_io_observed_trace"]

    propagation_match = re.search(
        r"TOP_AXI_METADATA_PROPAGATION_TRACE top_fsm_axi_attention_fixture "
        r"top_bits=(0x[0-9a-fA-F]+) top_bit_lsb=(\d+) top_bit_msb=(\d+) "
        r"layer_bits=(0x[0-9a-fA-F]+) nested_bits=(0x[0-9a-fA-F]+) "
        r"source=([a-zA-Z0-9_\.\[\]:/]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if propagation_match:
        bit_lsb = int(propagation_match.group(2))
        bit_msb = int(propagation_match.group(3))
        top_bits = int(propagation_match.group(1), 16)
        layer_bits = int(propagation_match.group(4), 16)
        nested_bits = int(propagation_match.group(5), 16)
        parsed["top_compact_status_axi_metadata_propagation"] = {
            "propagated": top_bits == layer_bits == nested_bits == 0xF,
            "top_status_bits_hex": propagation_match.group(1).lower(),
            "top_bit_lsb": bit_lsb,
            "top_bit_msb": bit_msb,
            "layer_status_bits_hex": propagation_match.group(4).lower(),
            "nested_axi_status_bits_hex": propagation_match.group(5).lower(),
            "child_source": propagation_match.group(6),
            "compact_status_hex": propagation_match.group(7).lower(),
            "bit_mapping": {
                "rid_good": bit_lsb,
                "rresp_good": bit_lsb + 1,
                "rlast_good": bit_lsb + 2,
                "all_metadata_good": bit_msb,
            },
            "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_top_compact_status",
        }
    else:
        parent_propagation_match = re.search(
            r"PARENT_AXI_METADATA_PROPAGATION_TRACE top_fsm_axi_attention_fixture "
            r"parent_bits=(0x[0-9a-fA-F]+) parent_mask=(0x[0-9a-fA-F]+) "
            r"parent_bit_lsb=(\d+) parent_bit_msb=(\d+) child_status_bits=(0x[0-9a-fA-F]+) "
            r"(?:q_bits=(0x[0-9a-fA-F]+) k_bits=(0x[0-9a-fA-F]+) v_bits=(0x[0-9a-fA-F]+) o_bits=(0x[0-9a-fA-F]+) )?"
            r"source=([a-zA-Z0-9_\.\[\]:]+) status=(0x[0-9a-fA-F]+)",
            output,
        )
        if parent_propagation_match:
            bit_lsb = int(parent_propagation_match.group(3))
            bit_msb = int(parent_propagation_match.group(4))
            top_bits = int(parent_propagation_match.group(1), 16)
            nested_bits = int(parent_propagation_match.group(5), 16)
            parsed["top_compact_status_axi_metadata_propagation"] = {
                "propagated": top_bits == nested_bits == 0xF,
                "top_status_bits_hex": parent_propagation_match.group(1).lower(),
                "top_bit_lsb": bit_lsb,
                "top_bit_msb": bit_msb,
                "layer_status_bits_hex": parent_propagation_match.group(5).lower(),
                "nested_axi_status_bits_hex": parent_propagation_match.group(5).lower(),
                "q_status_bits_hex": (parent_propagation_match.group(6) or "").lower() or None,
                "k_status_bits_hex": (parent_propagation_match.group(7) or "").lower() or None,
                "v_status_bits_hex": (parent_propagation_match.group(8) or "").lower() or None,
                "o_status_bits_hex": (parent_propagation_match.group(9) or "").lower() or None,
                "child_source": parent_propagation_match.group(10),
                "compact_status_hex": parent_propagation_match.group(11).lower(),
                "bit_mapping": {
                    "rid_good": bit_lsb,
                    "rresp_good": bit_lsb + 1,
                    "rlast_good": bit_lsb + 2,
                    "all_metadata_good": bit_msb,
                },
                "evidence_source": "parsed_from_top_fsm_axi_attention_testbench_aggregate_parent_compact_status",
            }
    return parsed


