def _parse_token_loop_axi_attention_fixture_sim_trace(output: str) -> dict[str, Any]:
    parsed: dict[str, Any] = {}
    token_match = re.search(
        r"TOKEN_LOOP_TRACE token_loop_axi_attention_fixture trace_hex=(0x[0-9a-fA-F]+) "
        r"events=([a-zA-Z0-9_,]+)",
        output,
    )
    if token_match:
        parsed["simulation_token_start_done_trace"] = {
            "recorded": True,
            "trace_hex": token_match.group(1),
            "ordered_events": token_match.group(2).split(","),
            "evidence_source": "parsed_from_token_loop_axi_attention_trace",
        }
        parsed["observed_token_start_done_trace"] = token_match.group(2).split(",")
    else:
        parsed["simulation_token_start_done_trace"] = {
            "recorded": False,
            "trace_hex": None,
            "ordered_events": [],
            "evidence_source": "parsed_from_token_loop_axi_attention_trace",
        }

    token_outputs: list[dict[str, Any]] = []
    top_traces: list[dict[str, Any]] = []
    layer_traces: list[dict[str, Any]] = []
    child_traces: list[dict[str, Any]] = []
    for match in re.finditer(
        r"TOKEN_CHILD_CALL_TRACE token_loop_axi_attention_fixture token=(\d+) "
        r"top_trace_hex=(0x[0-9a-fA-F]+) layer_trace_hex=(0x[0-9a-fA-F]+) "
        r"child_trace_hex=(0x[0-9a-fA-F]+) axi_bits=(0x[0-9a-fA-F]+) output=([-,\d]+)",
        output,
    ):
        token_idx = int(match.group(1))
        vector = _parse_attention_vector(match.group(6))
        token_outputs.append(
            {
                "token": token_idx,
                "output_vector": vector,
                "axi_metadata_bits_hex": match.group(5).lower(),
                "evidence_source": "parsed_from_token_loop_axi_testbench_captured_top_status",
            }
        )
        top_traces.append(
            {
                "token": token_idx,
                "ordered_events": ["layer_fsm_axi_attention_fixture_start", "layer_fsm_axi_attention_fixture_done"],
                "top_trace_hex": match.group(2),
                "layer_trace_hex": match.group(3),
                "child_trace_hex": match.group(4),
                "axi_metadata_bits_hex": match.group(5).lower(),
                "evidence_source": "parsed_from_token_loop_axi_testbench_captured_top_status",
            }
        )
        layer_traces.append(
            {
                "token": token_idx,
                "ordered_events": [
                    "decoder_child_axi_attention_datapath_start",
                    "decoder_child_axi_attention_datapath_done",
                ],
                "layer_trace_hex": match.group(3),
                "child_trace_hex": match.group(4),
                "evidence_source": "parsed_from_token_loop_axi_testbench_captured_top_status",
            }
        )
        child_traces.append(
            {
                "token": token_idx,
                "ordered_events": [
                    "source_path_start",
                    "source_path_done",
                    "projection_axi_start",
                    "projection_axi_done",
                    "attention_kv_start",
                    "attention_kv_done",
                ],
                "trace_hex": match.group(4),
                "evidence_source": "parsed_from_token_loop_axi_testbench_captured_top_status",
            }
        )
    if token_outputs:
        parsed["per_token_output_vectors"] = token_outputs
        parsed["token_output_vectors"] = [
            entry["output_vector"] for entry in sorted(token_outputs, key=lambda x: x["token"])
        ]
    if top_traces:
        parsed["top_fsm_traces"] = top_traces
    if layer_traces:
        parsed["layer_fsm_traces"] = layer_traces
    if child_traces:
        parsed["decoder_child_traces"] = child_traces

    hold_entries: list[dict[str, Any]] = []
    for match in re.finditer(
        r"TOKEN_CHILD_START_HOLD_TRACE token_loop_axi_attention_fixture token=(\d+) "
        r"busy_cycles=(\d+) done_seen_while_start_high=(\d+) "
        r"deasserted_after_done=(\d+) release_seen=(\d+)",
        output,
    ):
        hold_entries.append(
            {
                "token": int(match.group(1)),
                "busy_cycles": int(match.group(2)),
                "done_seen_while_start_high": bool(int(match.group(3))),
                "deasserted_after_done": bool(int(match.group(4))),
                "done_release_seen_after_start_deassert": bool(int(match.group(5))),
                "evidence_source": "parsed_from_token_loop_axi_testbench_top_child_start_monitor",
            }
        )
    if hold_entries:
        parsed["per_token_child_start_hold_deassert_release_evidence"] = hold_entries
        parsed["child_start_hold_deassert_release_evidence"] = hold_entries

    propagation_match = re.search(
        r"TOKEN_AXI_METADATA_PROPAGATION_TRACE token_loop_axi_attention_fixture "
        r"token_bits=(0x[0-9a-fA-F]+) token_bit_lsb=(\d+) token_bit_msb=(\d+) "
        r"top_bits=(0x[0-9a-fA-F]+) layer_bits=(0x[0-9a-fA-F]+) "
        r"nested_bits=(0x[0-9a-fA-F]+) source=([a-zA-Z0-9_\.\[\]:]+) "
        r"status=(0x[0-9a-fA-F]+)",
        output,
    )
    if propagation_match:
        bit_lsb = int(propagation_match.group(2))
        bit_msb = int(propagation_match.group(3))
        token_bits = int(propagation_match.group(1), 16)
        top_bits = int(propagation_match.group(4), 16)
        layer_bits = int(propagation_match.group(5), 16)
        nested_bits = int(propagation_match.group(6), 16)
        parsed["token_loop_compact_status_axi_metadata_propagation"] = {
            "propagated": token_bits == top_bits == layer_bits == nested_bits == 0xF,
            "token_status_bits_hex": propagation_match.group(1).lower(),
            "token_bit_lsb": bit_lsb,
            "token_bit_msb": bit_msb,
            "top_status_bits_hex": propagation_match.group(4).lower(),
            "layer_status_bits_hex": propagation_match.group(5).lower(),
            "nested_axi_status_bits_hex": propagation_match.group(6).lower(),
            "child_source": propagation_match.group(7),
            "compact_status_hex": propagation_match.group(8).lower(),
            "bit_mapping": {
                "rid_good": bit_lsb,
                "rresp_good": bit_lsb + 1,
                "rlast_good": bit_lsb + 2,
                "all_metadata_good": bit_msb,
            },
            "evidence_source": "parsed_from_token_loop_axi_testbench_parent_compact_status",
        }

    top_axi_match = re.search(
        r"TOP_AXI_ATTENTION_TRACE token_loop_axi_attention_fixture token=(\d+) "
        r"top_trace_hex=(0x[0-9a-fA-F]+) layer_trace_hex=(0x[0-9a-fA-F]+) "
        r"child_trace_hex=(0x[0-9a-fA-F]+) events=([a-zA-Z0-9_,]+)",
        output,
    )
    if top_axi_match:
        parsed["simulation_top_trace"] = {
            "recorded": True,
            "token": int(top_axi_match.group(1)),
            "top_trace_hex": top_axi_match.group(2),
            "layer_trace_hex": top_axi_match.group(3),
            "child_trace_hex": top_axi_match.group(4),
            "ordered_events": top_axi_match.group(5).split(","),
            "evidence_source": "observed_through_token_loop_axi_top_child_hierarchy",
        }

    normalized = output.replace("token_loop_axi_attention_fixture", "decoder_child_axi_attention_datapath")
    child_parsed = _parse_decoder_child_axi_attention_datapath_sim_trace(normalized)
    projection_summary: dict[str, Any] = {
        "evidence_source": "parsed_from_token_loop_axi_testbench_nested_child_signals_token1"
    }
    ar_match = re.search(
        r"AXI_PROJECTION_AR_TRACE token_loop_axi_attention_fixture addr=(0x[0-9a-fA-F]+) "
        r"len=(\d+) size=(\d+) burst=(\d+) id=(0x[0-9a-fA-F]+) beats=(\d+)",
        output,
    )
    if ar_match:
        projection_summary["command_trace"] = {
            "addr_hex": ar_match.group(1).lower(),
            "axi_arlen": int(ar_match.group(2)),
            "axi_arsize": int(ar_match.group(3)),
            "axi_arburst": int(ar_match.group(4)),
            "axi_arid_hex": ar_match.group(5).lower(),
            "request_beat_count": int(ar_match.group(6)),
            "evidence_source": "parsed_from_token_loop_axi_testbench_axi_child_ar_trace",
        }
    metadata_match = re.search(
        r"AXI_PROJECTION_R_METADATA_TRACE token_loop_axi_attention_fixture accepted=(0x[0-9a-fA-F]+) "
        r"last=(0x[0-9a-fA-F]+) rid_ok=(\d+) rresp_ok=(\d+) rlast_ok=(\d+)",
        output,
    )
    if metadata_match:
        projection_summary["r_metadata_trace"] = {
            "accepted_trace_hex": metadata_match.group(1).lower(),
            "rlast_trace_hex": metadata_match.group(2).lower(),
            "rid_ok": bool(int(metadata_match.group(3))),
            "rresp_ok": bool(int(metadata_match.group(4))),
            "rlast_ok": bool(int(metadata_match.group(5))),
            "evidence_source": "parsed_from_token_loop_axi_testbench_axi_child_r_metadata",
        }
    payload_match = re.search(
        r"AXI_PROJECTION_PAYLOAD_TRACE token_loop_axi_attention_fixture emitted=(\d+) "
        r"consumed=(\d+) payload_match=(\d+) first=(0x[0-9a-fA-F]+) last=(0x[0-9a-fA-F]+)",
        output,
    )
    if payload_match:
        projection_summary["payload_trace"] = {
            "emitted_count": int(payload_match.group(1)),
            "consumed_count": int(payload_match.group(2)),
            "payload_link_match_passed": bool(int(payload_match.group(3))),
            "first_payload_hex": payload_match.group(4).lower(),
            "last_payload_hex": payload_match.group(5).lower(),
            "evidence_source": "parsed_from_token_loop_axi_testbench_axi_child_payload_trace",
        }
    backpressure_match = re.search(
        r"AXI_PROJECTION_BACKPRESSURE_TRACE token_loop_axi_attention_fixture ready_low_payload_idx=([0-9,]+) "
        r"trace=(0x[0-9a-fA-F]+) payload_hold_ok=(\d+)",
        output,
    )
    if backpressure_match:
        projection_summary["backpressure_trace"] = {
            "ready_low_payload_indices": [
                int(value) for value in backpressure_match.group(1).split(",") if value != ""
            ],
            "ready_low_trace_hex": backpressure_match.group(2).lower(),
            "payload_valid_held_while_ready_low": bool(int(backpressure_match.group(3))),
            "evidence_source": "parsed_from_token_loop_axi_testbench_axi_child_backpressure_trace",
        }
    output_match = re.search(
        r"AXI_PROJECTION_OUTPUT_TRACE token_loop_axi_attention_fixture output=(-?\d+),(-?\d+)",
        output,
    )
    if output_match:
        projection_summary["output_trace"] = {
            "projection_output_vector": [int(output_match.group(1)), int(output_match.group(2))],
            "evidence_source": "parsed_from_token_loop_axi_testbench_axi_child_output",
        }
    round_trip_match = re.search(
        r"AXI_PROJECTION_ROUND_TRIP_TRACE token_loop_axi_attention_fixture packed_bytes=(\d+) "
        r"unpacked_values=(\d+) round_trip_passed=(\d+)",
        output,
    )
    if round_trip_match:
        projection_summary["round_trip_evidence"] = {
            "packed_bytes": int(round_trip_match.group(1)),
            "unpacked_values": int(round_trip_match.group(2)),
            "round_trip_passed": bool(int(round_trip_match.group(3))),
            "evidence_source": "parsed_from_token_loop_axi_testbench_axi_child_round_trip",
        }
    if len(projection_summary) > 1:
        parsed["nested_axi_projection_evidence_summary"] = projection_summary
    if (
        "axi_projection_child_observed_command_trace" in child_parsed
        or "axi_projection_child_observed_r_metadata_trace" in child_parsed
        or "axi_projection_child_payload_trace" in child_parsed
    ):
        existing_projection_summary = dict(parsed.get("nested_axi_projection_evidence_summary", {}))
        merged_payload_trace = dict(existing_projection_summary.get("payload_trace", {}))
        merged_payload_trace.update(child_parsed.get("axi_projection_child_payload_trace") or {})
        parsed["nested_axi_projection_evidence_summary"] = {
            "evidence_source": "parsed_from_token_loop_axi_testbench_nested_child_signals_token1",
            "command_trace": child_parsed.get("axi_projection_child_observed_command_trace")
            or existing_projection_summary.get("command_trace"),
            "r_metadata_trace": child_parsed.get("axi_projection_child_observed_r_metadata_trace")
            or existing_projection_summary.get("r_metadata_trace"),
            "payload_trace": merged_payload_trace,
            "backpressure_trace": child_parsed.get("axi_projection_child_backpressure_trace")
            or existing_projection_summary.get("backpressure_trace"),
            "output_trace": child_parsed.get("axi_projection_child_observed_output_trace")
            or existing_projection_summary.get("output_trace"),
            "round_trip_evidence": child_parsed.get("axi_projection_child_round_trip_evidence")
            or existing_projection_summary.get("round_trip_evidence"),
        }
    if (
        "attention_kv_observed_write_trace" in child_parsed
        or "attention_kv_observed_key_read_trace" in child_parsed
        or "attention_kv_observed_score_trace" in child_parsed
    ):
        parsed["nested_attention_kv_evidence_summary"] = {
            "evidence_source": "parsed_from_token_loop_axi_testbench_nested_child_signals_token1",
            "cache_write_trace": child_parsed.get("attention_kv_observed_write_trace"),
            "key_read_trace": child_parsed.get("attention_kv_observed_key_read_trace"),
            "value_read_trace": child_parsed.get("attention_kv_observed_value_read_trace"),
            "attention_score_trace": child_parsed.get("attention_kv_observed_score_trace"),
            "softmax_control_trace": child_parsed.get("attention_kv_observed_softmax_control_trace"),
        }

    final_match = re.search(
        r"FINAL_OUTPUT_TRACE token_loop_axi_attention_fixture output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if final_match:
        parsed["observed_final_fixture_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["final_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_compact_status_hex"] = final_match.group(2)
    stable_match = re.search(r"TOKEN_LOOP_STABILITY_TRACE token_loop_axi_attention_fixture stable=(\d+)", output)
    if stable_match:
        parsed["loop_done_output_status_stability_observed"] = bool(int(stable_match.group(1)))
    repeat_match = re.search(
        r"TOKEN_OUTPUT_POLICY_TRACE token_loop_axi_attention_fixture repeated_deterministic_outputs=(\d+) "
        r"token_dependent_outputs=(\d+)",
        output,
    )
    if repeat_match:
        parsed["repeated_deterministic_fixture_outputs"] = bool(int(repeat_match.group(1)))
        parsed["token_outputs_are_token_dependent"] = bool(int(repeat_match.group(2)))
    compact_match = re.search(
        r"COMPACT_IO_TRACE token_loop_axi_attention_fixture estimated_iob_bits=(\d+) "
        r"prior_top_fsm_bonded_iob=(\d+) prior_top_fsm_status_bits=(\d+) "
        r"exposed_child_vectors=(\d+) exposed_wide_status=(\d+) exposed_128b_axi_data=(\d+) "
        r"exposed_kv_arrays=(\d+) exposed_axi_debug=(\d+)",
        output,
    )
    if compact_match:
        parsed["compact_io_observed_trace"] = {
            "estimated_iob_bits": int(compact_match.group(1)),
            "prior_top_fsm_bonded_iob_reference": int(compact_match.group(2)),
            "prior_top_fsm_status_bits": int(compact_match.group(3)),
            "exposes_child_vectors": bool(int(compact_match.group(4))),
            "exposes_wide_status": bool(int(compact_match.group(5))),
            "exposes_128b_axi_read_data": bool(int(compact_match.group(6))),
            "exposes_full_kv_arrays": bool(int(compact_match.group(7))),
            "exposes_axi_debug_buses": bool(int(compact_match.group(8))),
            "evidence_source": "parsed_from_token_loop_axi_testbench_compact_io_trace",
        }
    return parsed


