    mlp_final_match = re.search(r"MLP_FINAL_TRACE layer_fsm_decoder_block_fixture output=([-,\d]+)", output)
    if mlp_final_match:
        parsed["mlp_final_output_vector"] = _parse_attention_vector(mlp_final_match.group(1))

    block_final_match = re.search(
        r"FINAL_DECODER_BLOCK_OUTPUT_TRACE layer_fsm_decoder_block_fixture output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if block_final_match:
        parsed["decoder_block_child_output_vector"] = _parse_attention_vector(block_final_match.group(1))
        parsed["decoder_block_child_status_hex"] = block_final_match.group(2)
    final_match = re.search(
        r"FINAL_OUTPUT_TRACE layer_fsm_decoder_block_fixture output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if final_match:
        parsed["final_layer_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_final_fixture_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_compact_status_hex"] = final_match.group(2)
    stable_match = re.search(r"LAYER_STABILITY_TRACE layer_fsm_decoder_block_fixture stable=(\d+)", output)
    if stable_match:
        parsed["layer_done_output_status_stability_observed"] = bool(int(stable_match.group(1)))
    compact_match = re.search(
        r"COMPACT_IO_TRACE layer_fsm_decoder_block_fixture estimated_iob_bits=(\d+) previous_decoder_block_iob=(\d+) exposed_child_vectors=(\d+) exposed_wide_status=(\d+) exposed_128b=(\d+) exposed_kv_arrays=(\d+)",
        output,
    )
    if compact_match:
        parsed["compact_io_observed_trace"] = {
            "estimated_iob_bits": int(compact_match.group(1)),
            "previous_decoder_block_iob_reference": int(compact_match.group(2)),
            "exposes_child_vectors": bool(int(compact_match.group(3))),
            "exposes_wide_status": bool(int(compact_match.group(4))),
            "exposes_128b_memory_response": bool(int(compact_match.group(5))),
            "exposes_full_kv_arrays": bool(int(compact_match.group(6))),
            "evidence_source": "parsed_from_layer_fsm_decoder_block_testbench_compact_io_trace",
        }
    return parsed


