def _parse_layer_fsm_axi_decoder_block_fixture_sim_trace(output: str) -> dict[str, Any]:
    parsed: dict[str, Any] = {}
    layer_match = re.search(
        r"LAYER_AXI_DECODER_BLOCK_TRACE layer_fsm_axi_decoder_block_fixture "
        r"layer_trace_hex=(0x[0-9a-fA-F]+) block_trace_hex=(0x[0-9a-fA-F]+) "
        r"axi_metadata_bits=(0x[0-9a-fA-F]+) events=([a-zA-Z0-9_,]+)",
        output,
    )
    if layer_match:
        parsed["simulation_layer_trace"] = {
            "recorded": True,
            "layer_trace_hex": layer_match.group(1),
            "block_trace_hex": layer_match.group(2),
            "axi_metadata_bits_hex": layer_match.group(3).lower(),
            "ordered_events": layer_match.group(4).split(","),
            "evidence_source": "parsed_from_layer_fsm_axi_decoder_block_testbench_status",
        }
        parsed["ordered_layer_trace"] = layer_match.group(4).split(",")
    else:
        parsed["simulation_layer_trace"] = {
            "recorded": False,
            "layer_trace_hex": None,
            "block_trace_hex": None,
            "axi_metadata_bits_hex": None,
            "ordered_events": [],
            "evidence_source": "parsed_from_layer_fsm_axi_decoder_block_testbench_status",
        }

    normalized = output.replace("layer_fsm_axi_decoder_block_fixture", "decoder_block_axi_attention_mlp_fixture")
    block_parsed = _parse_decoder_block_axi_attention_mlp_fixture_sim_trace(normalized)
    parsed.update(block_parsed)
    for child in parsed.get("axi_projection_children_observed", {}).values():
        for trace_key in (
            "command_trace",
            "r_metadata_trace",
            "payload_trace",
            "output_trace",
            "round_trip_evidence",
        ):
            trace = child.get(trace_key)
            if isinstance(trace, dict) and isinstance(trace.get("instance"), str):
                trace["instance"] = trace["instance"].replace(
                    "u_decoder_child_axi_attention_datapath.u_decoder_child_axi_attention_datapath.",
                    "u_decoder_block_axi_attention_mlp_fixture.u_decoder_child_axi_attention_datapath.",
                )

    propagation_match = re.search(
        r"LAYER_AXI_METADATA_PROPAGATION_TRACE layer_fsm_axi_decoder_block_fixture "
        r"layer_bits=(0x[0-9a-fA-F]+) layer_bit_lsb=(\d+) layer_bit_msb=(\d+) "
        r"child_block_bits=(0x[0-9a-fA-F]+) q_bits=(0x[0-9a-fA-F]+) "
        r"k_bits=(0x[0-9a-fA-F]+) v_bits=(0x[0-9a-fA-F]+) o_bits=(0x[0-9a-fA-F]+) "
        r"source=([a-zA-Z0-9_\.\[\]:]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if propagation_match:
        bit_lsb = int(propagation_match.group(2))
        bit_msb = int(propagation_match.group(3))
        layer_bits = int(propagation_match.group(1), 16)
        child_bits = int(propagation_match.group(4), 16)
        parsed["layer_compact_status_axi_metadata_propagation"] = {
            "propagated": layer_bits == child_bits == 0xF,
            "layer_status_bits_hex": propagation_match.group(1).lower(),
            "layer_bit_lsb": bit_lsb,
            "layer_bit_msb": bit_msb,
            "child_block_status_bits_hex": propagation_match.group(4).lower(),
            "q_status_bits_hex": propagation_match.group(5).lower(),
            "k_status_bits_hex": propagation_match.group(6).lower(),
            "v_status_bits_hex": propagation_match.group(7).lower(),
            "o_status_bits_hex": propagation_match.group(8).lower(),
            "child_source": propagation_match.group(9),
            "compact_status_hex": propagation_match.group(10).lower(),
            "bit_mapping": {
                "rid_good": bit_lsb,
                "rresp_good": bit_lsb + 1,
                "rlast_good": bit_lsb + 2,
                "all_metadata_good": bit_msb,
            },
            "evidence_source": "parsed_from_layer_fsm_axi_decoder_block_testbench_compact_status",
        }

    hold_match = re.search(
        r"LAYER_BLOCK_CHILD_START_HOLD_TRACE layer_fsm_axi_decoder_block_fixture "
        r"busy_cycles=(\d+) done_seen_while_start_high=(\d+) deasserted_after_done=(\d+) release_seen=(\d+)",
        output,
    )
    if hold_match:
        parsed["layer_to_block_child_start_hold_deassert_release_evidence"] = {
            "busy_cycles": int(hold_match.group(1)),
            "done_seen_while_start_high": bool(int(hold_match.group(2))),
            "start_deasserted_after_done": bool(int(hold_match.group(3))),
            "done_release_seen_after_start_deassert": bool(int(hold_match.group(4))),
            "evidence_source": "observed_in_layer_fsm_axi_decoder_block_testbench",
        }

    block_final_match = re.search(
        r"FINAL_DECODER_BLOCK_OUTPUT_TRACE layer_fsm_axi_decoder_block_fixture "
        r"output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if block_final_match:
        parsed["decoder_block_child_output_vector"] = _parse_attention_vector(block_final_match.group(1))
        parsed["decoder_block_child_status_hex"] = block_final_match.group(2)
    final_match = re.search(
        r"FINAL_OUTPUT_TRACE layer_fsm_axi_decoder_block_fixture output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if final_match:
        parsed["final_layer_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_final_fixture_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_compact_status_hex"] = final_match.group(2)
    stable_match = re.search(r"LAYER_STABILITY_TRACE layer_fsm_axi_decoder_block_fixture stable=(\d+)", output)
    if stable_match:
        parsed["layer_done_output_status_stability_observed"] = bool(int(stable_match.group(1)))
    compact_match = re.search(
        r"COMPACT_IO_TRACE layer_fsm_axi_decoder_block_fixture estimated_iob_bits=(\d+) "
        r"previous_decoder_block_iob=(\d+) exposed_child_vectors=(\d+) exposed_wide_status=(\d+) "
        r"exposed_128b_axi_data=(\d+) exposed_axi_debug=(\d+) exposed_kv_arrays=(\d+)",
        output,
    )
    if compact_match:
        parsed["compact_io_observed_trace"] = {
            "estimated_iob_bits": int(compact_match.group(1)),
            "previous_decoder_block_iob_reference": int(compact_match.group(2)),
            "exposes_child_vectors": bool(int(compact_match.group(3))),
            "exposes_wide_status": bool(int(compact_match.group(4))),
            "exposes_128b_axi_data": bool(int(compact_match.group(5))),
            "exposes_axi_debug_buses": bool(int(compact_match.group(6))),
            "exposes_full_kv_arrays": bool(int(compact_match.group(7))),
            "evidence_source": "parsed_from_layer_fsm_axi_decoder_block_testbench_compact_io_trace",
        }
    if parsed.get("attention_to_mlp_consumption_observed") is True:
        parsed["decoder_block_consumed_attention_output_into_mlp"] = {
            "observed_through_layer_hierarchy": True,
            "attention_output_vector": parsed.get("captured_attention_output_vector"),
            "mlp_attention_input_vector": parsed.get("mlp_attention_input_vector"),
            "evidence_source": "observed_through_layer_fsm_axi_decoder_block_hierarchy",
        }
    return parsed


