def _ddr_axi_board_shell_stream_plan(config: AgentConfig) -> dict[str, Any]:
    semantic_graph = build_llama_semantic_graph("meta-llama/Llama-3.2-1B", config)
    manifest = build_hdl_task_manifest(semantic_graph, config)
    return manifest["projection_weight_stream_plan"]


def _compact_projection_stream_summary(stream_plan: dict[str, Any]) -> list[dict[str, Any]]:
    return [
        {
            "name": item["name"],
            "decoder_use": item["decoder_use"],
            "rows": item["rows"],
            "cols": item["cols"],
            "packed_int4_bytes": item["packed_int4_bytes"],
            "memory_beats": item["memory_beats"],
            "target_checkpoint_layout_dependency": item["target_checkpoint_layout_dependency"],
            "target_checkpoint_payload_dependency": item["target_checkpoint_payload_dependency"],
            "qweight_payload_word_count": item["qweight_payload_word_count"],
            "qweight_payload_covers_first_memory_beat": item["qweight_payload_covers_first_memory_beat"],
        }
        for item in stream_plan["projections"]
    ]


def _parse_ddr_axi_board_shell_fixture_sim_trace(output: str) -> dict[str, Any]:
    parsed: dict[str, Any] = {}
    trace_match = re.search(
        r"DDR_AXI_BOARD_SHELL_TRACE ddr_axi_board_shell_fixture "
        r"shell_trace_hex=(0x[0-9a-fA-F]+) model_trace_hex=(0x[0-9a-fA-F]+) "
        r"request_mask=(0x[0-9a-fA-F]+) attention_mask=(0x[0-9a-fA-F]+) "
        r"mlp_mask=(0x[0-9a-fA-F]+) events=([a-zA-Z0-9_,]+)",
        output,
    )
    if trace_match:
        parsed["simulation_board_shell_start_done_trace"] = {
            "recorded": True,
            "shell_trace_hex": trace_match.group(1).lower(),
            "model_trace_hex": trace_match.group(2).lower(),
            "all_projection_request_mask_hex": trace_match.group(3).lower(),
            "attention_request_mask_hex": trace_match.group(4).lower(),
            "mlp_request_mask_hex": trace_match.group(5).lower(),
            "ordered_events": trace_match.group(6).split(","),
            "evidence_source": "parsed_from_ddr_axi_board_shell_testbench_status",
        }
        parsed["observed_board_shell_start_done_trace"] = trace_match.group(6).split(",")

    hold_match = re.search(
        r"DDR_AXI_MODEL_CHILD_START_HOLD_TRACE ddr_axi_board_shell_fixture "
        r"busy_cycles=(\d+) done_seen_while_start_high=(\d+) "
        r"deasserted_after_done=(\d+) release_seen=(\d+)",
        output,
    )
    if hold_match:
        parsed["shell_to_model_child_start_hold_deassert_release_evidence"] = {
            "busy_cycles": int(hold_match.group(1)),
            "done_seen_while_start_high": bool(int(hold_match.group(2))),
            "start_deasserted_after_done": bool(int(hold_match.group(3))),
            "done_release_seen_after_start_deassert": bool(int(hold_match.group(4))),
            "evidence_source": "parsed_from_ddr_axi_board_shell_testbench_model_child_monitor",
        }

    request_entries: list[dict[str, Any]] = []
    for match in re.finditer(
        r"DDR_AXI_PROJECTION_REQUEST_TRACE ddr_axi_board_shell_fixture "
        r"projection=([a-z_]+) decoder_use=([a-z]+) rows=(\d+) cols=(\d+) "
        r"packed_int4_bytes=(\d+) memory_beats=(\d+) "
        r"layout_dependency=([a-zA-Z0-9_]+) payload_dependency=([a-zA-Z0-9_]+) "
        r"request_bit=(\d+) status_bit=(\d+) source=([a-zA-Z0-9_./]+)",
        output,
    ):
        request_entries.append(
            {
                "projection": match.group(1),
                "decoder_use": match.group(2),
                "rows": int(match.group(3)),
                "cols": int(match.group(4)),
                "packed_int4_bytes": int(match.group(5)),
                "memory_beats": int(match.group(6)),
                "target_checkpoint_layout_dependency": match.group(7),
                "target_checkpoint_payload_dependency": match.group(8),
                "request_bit": int(match.group(9)),
                "status_bit": bool(int(match.group(10))),
                "source": match.group(11),
                "evidence_source": "parsed_from_ddr_axi_board_shell_projection_request_trace",
            }
        )
    if request_entries:
        parsed["observed_projection_request_status_metadata"] = request_entries
        parsed["observed_projection_request_count"] = len(request_entries)
        parsed["observed_attention_projection_request_count"] = sum(
            1 for entry in request_entries if entry["decoder_use"] == "attention"
        )
        parsed["observed_mlp_projection_request_count"] = sum(
            1 for entry in request_entries if entry["decoder_use"] == "mlp"
        )

    compact_match = re.search(
        r"DDR_AXI_COMPACT_STATUS_TRACE ddr_axi_board_shell_fixture "
        r"projection_count=(\d+) model_bits=(0x[0-9a-fA-F]+) "
        r"request_mask=(0x[0-9a-fA-F]+) attention_mask=(0x[0-9a-fA-F]+) "
        r"mlp_mask=(0x[0-9a-fA-F]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if compact_match:
        parsed["compact_axi_request_status_observed"] = {
            "projection_count": int(compact_match.group(1)),
            "model_axi_metadata_bits_hex": compact_match.group(2).lower(),
            "all_projection_request_mask_hex": compact_match.group(3).lower(),
            "attention_request_mask_hex": compact_match.group(4).lower(),
            "mlp_request_mask_hex": compact_match.group(5).lower(),
            "compact_status_hex": compact_match.group(6).lower(),
            "evidence_source": "parsed_from_ddr_axi_board_shell_compact_status_trace",
        }

    final_match = re.search(
        r"FINAL_OUTPUT_TRACE ddr_axi_board_shell_fixture output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if final_match:
        parsed["observed_final_fixture_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["final_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_compact_status_hex"] = final_match.group(2)
    stable_match = re.search(r"DDR_AXI_BOARD_SHELL_STABILITY_TRACE ddr_axi_board_shell_fixture stable=(\d+)", output)
    if stable_match:
        parsed["shell_done_output_status_stability_observed"] = bool(int(stable_match.group(1)))
    compact_io_match = re.search(
        r"COMPACT_IO_TRACE ddr_axi_board_shell_fixture estimated_iob_bits=(\d+) "
        r"prior_model_fsm_axi_bonded_iob=(\d+) prior_model_fsm_axi_status_bits=(\d+) "
        r"exposed_child_vectors=(\d+) exposed_wide_status=(\d+) exposed_128b_axi_data=(\d+) "
        r"exposed_axi_debug=(\d+) exposed_kv_arrays=(\d+) board_io_constraints=(\d+)",
        output,
    )
    if compact_io_match:
        parsed["compact_io_observed_trace"] = {
            "estimated_iob_bits": int(compact_io_match.group(1)),
            "prior_model_fsm_axi_bonded_iob_reference": int(compact_io_match.group(2)),
            "prior_model_fsm_axi_status_bits": int(compact_io_match.group(3)),
            "exposes_child_vectors": bool(int(compact_io_match.group(4))),
            "exposes_wide_status": bool(int(compact_io_match.group(5))),
            "exposes_128b_axi_data": bool(int(compact_io_match.group(6))),
            "exposes_axi_debug_buses": bool(int(compact_io_match.group(7))),
            "exposes_full_kv_arrays": bool(int(compact_io_match.group(8))),
            "board_io_constraints_present": bool(int(compact_io_match.group(9))),
            "evidence_source": "parsed_from_ddr_axi_board_shell_compact_io_trace",
        }
    return parsed


