def _parse_residual_mlp_fixture_sim_trace(output: str) -> dict[str, Any]:
    parsed: dict[str, Any] = {}
    trace_match = re.search(
        r"RESIDUAL_MLP_TRACE residual_mlp_fixture trace_hex=(0x[0-9a-fA-F]+) events=([a-zA-Z0-9_,]+)",
        output,
    )
    if trace_match:
        parsed["simulation_residual_mlp_trace"] = {
            "recorded": True,
            "trace_hex": trace_match.group(1),
            "ordered_events": trace_match.group(2).split(","),
            "evidence_source": "parsed_from_residual_mlp_testbench_status_trace",
        }
        parsed["ordered_residual_mlp_trace"] = trace_match.group(2).split(",")
    else:
        parsed["simulation_residual_mlp_trace"] = {
            "recorded": False,
            "trace_hex": None,
            "ordered_events": [],
            "evidence_source": "parsed_from_residual_mlp_testbench_status_trace",
        }

    hidden_match = re.search(
        r"HIDDEN_INPUT_TRACE residual_mlp_fixture hidden=([-,\d]+) attention=([-,\d]+)",
        output,
    )
    if hidden_match:
        parsed["observed_hidden_input_vector"] = _parse_attention_vector(hidden_match.group(1))
        parsed["observed_attention_output_vector"] = _parse_attention_vector(hidden_match.group(2))
    residual_match = re.search(r"RESIDUAL0_TRACE residual_mlp_fixture residual0=([-,\d]+)", output)
    if residual_match:
        parsed["observed_residual0_vector"] = _parse_attention_vector(residual_match.group(1))
        parsed["observed_mlp_norm_input_vector"] = _parse_attention_vector(residual_match.group(1))
    gate_match = re.search(
        r"GATE_UP_TRACE residual_mlp_fixture gate=([-,\d]+) up=([-,\d]+) source=([a-zA-Z0-9_]+)",
        output,
    )
    if gate_match:
        parsed["observed_gate_projection_vector"] = _parse_attention_vector(gate_match.group(1))
        parsed["observed_up_projection_vector"] = _parse_attention_vector(gate_match.group(2))
        parsed["observed_gate_up_projection_source"] = gate_match.group(3)
    swiglu_match = re.search(
        r"SWIGLU_TRACE residual_mlp_fixture policy=([a-zA-Z0-9_]+) swiglu=([-,\d]+) true_silu_exp=(\d+)",
        output,
    )
    if swiglu_match:
        parsed["observed_swiglu_vector"] = _parse_attention_vector(swiglu_match.group(2))
        parsed["observed_arithmetic_policy"] = {
            "policy": swiglu_match.group(1),
            "true_silu_or_exponential_math_implemented_in_rtl": bool(int(swiglu_match.group(3))),
            "evidence_source": "parsed_from_residual_mlp_testbench_swiglu_trace",
        }
    down_match = re.search(
        r"DOWN_TRACE residual_mlp_fixture down=([-,\d]+) source=([a-zA-Z0-9_]+)",
        output,
    )
    if down_match:
        parsed["observed_down_projection_vector"] = _parse_attention_vector(down_match.group(1))
        parsed["observed_down_projection_source"] = down_match.group(2)
    final_match = re.search(
        r"FINAL_OUTPUT_TRACE residual_mlp_fixture output=([-,\d]+) status=(0x[0-9a-fA-F]+)",
        output,
    )
    if final_match:
        parsed["observed_final_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["final_output_vector"] = _parse_attention_vector(final_match.group(1))
        parsed["observed_compact_status_hex"] = final_match.group(2)
    stable_match = re.search(r"RESIDUAL_MLP_STABILITY_TRACE residual_mlp_fixture stable=(\d+)", output)
    if stable_match:
        parsed["done_output_status_stability_observed"] = bool(int(stable_match.group(1)))
    compact_match = re.search(
        r"COMPACT_IO_TRACE residual_mlp_fixture estimated_iob_bits=(\d+) exposed_128b_memory_response=(\d+) exposed_full_hidden_vectors=(\d+) exposed_intermediate_tensors=(\d+) exposed_matrices=(\d+) exposed_debug_arrays=(\d+)",
        output,
    )
    if compact_match:
        parsed["compact_io_observed_trace"] = {
            "estimated_iob_bits": int(compact_match.group(1)),
            "exposes_128b_memory_response": bool(int(compact_match.group(2))),
            "exposes_full_hidden_vectors": bool(int(compact_match.group(3))),
            "exposes_full_intermediate_tensors": bool(int(compact_match.group(4))),
            "exposes_full_matrices": bool(int(compact_match.group(5))),
            "exposes_full_debug_arrays": bool(int(compact_match.group(6))),
            "evidence_source": "parsed_from_residual_mlp_testbench_compact_io_trace",
        }
    return parsed


